// Read Bid Tracker for each active project
// n8n: this node aggregates bid data from all projects with a Bid Tracker Sheet ID
const projects = $input.all().map(i => i.json);
const active = projects.filter(p =>
    p['Bid Tracker Sheet ID'] && p['Bid Tracker Sheet ID'].trim() &&
    (p['Status'] || '').toLowerCase() !== 'complete' &&
    (p['Status'] || '').toLowerCase() !== 'closed'
);

if (active.length === 0) {
    return [{ json: { error: 'No active projects with Bid Tracker Sheet IDs', projects: [] } }];
}

// Return each project so the next node (Split) can process them one at a time
return active.map(p => ({ json: {
    projectName:       p['Project Name'] || '',
    bidTrackerSheetId: (p['Bid Tracker Sheet ID'] || '').trim(),
    tabName:           'Sheet1',
} }));

// ─────────────────────────────────────────────────────────────────
// INPUT: all bids from bid tracker (concatenated across all projects)
// ─────────────────────────────────────────────────────────────────
const projects = $('Load Project Registry').all().map(i => i.json);
const bids     = $input.all().map(i => i.json);
const today    = new Date();
today.setHours(0,0,0,0);

// Grace period: 3 days after bid due date before sending follow-up
const GRACE_DAYS = 3;
const MS_DAY = 86400000;

const overdue = [];

for (const bid of bids) {
    const status = (bid['Status'] || '').trim();
    // Only follow up on bids that were "Sent" but never received
    if (!['Sent', 'Pending', 'Invited', 'No Response'].includes(status)) continue;

    // Check follow-up already sent
    if (bid['Follow Up Sent'] && bid['Follow Up Sent'].trim()) continue;

    const dateSent = bid['Date Sent'] ? new Date(bid['Date Sent']) : null;
    if (!dateSent || isNaN(dateSent)) continue;

    const daysSince = Math.floor((today - dateSent) / MS_DAY);
    if (daysSince < GRACE_DAYS) continue;  // Too soon

    const vendor   = (bid['Vendor']   || 'Vendor').trim();
    const contact  = (bid['Contact']  || '').trim();
    const email    = (bid['Email']    || '').trim();
    const trade    = (bid['Trade']    || '').trim();
    const division = (bid['CSI Division'] || '').trim();
    const project  = (bid['Project Name'] || '').trim();
    const rowNum   = bid['__rowNum']  || '';  // n8n appends row numbers if available

    if (!email) continue;  // Cannot follow up without email

    overdue.push({
        vendor, contact, email, trade, division, project, daysSince,
        dateSent: dateSent.toISOString().split('T')[0],
        rowNum,
    });
}

if (overdue.length === 0) {
    return [{ json: { hasOverdue: false, count: 0, bids: [] } }];
}

return [{ json: { hasOverdue: true, count: overdue.length, bids: overdue } }];

const data = $input.first().json;
if (!data.hasOverdue) return [{ json: { skipped: true, reason: 'No overdue bids' } }];

const bids = data.bids;
const today = new Date().toISOString().split('T')[0];

// Group by vendor email to avoid duplicate follow-ups to same vendor
const byEmail = {};
for (const bid of bids) {
    if (!byEmail[bid.email]) byEmail[bid.email] = [];
    byEmail[bid.email].push(bid);
}

const drafts = [];
for (const [email, vendorBids] of Object.entries(byEmail)) {
    const first = vendorBids[0];
    const tradeLine = vendorBids.map(b => `${b.division ? b.division + ' — ' : ''}${b.trade} (${b.project})`).join(', ');

    const subject = `Follow-Up: Bid Request — ${first.vendor} — ${first.trade}`;
    const body = `Hi ${first.contact || first.vendor},

I wanted to follow up on our bid request sent ${first.dateSent}. We have not yet received your bid for:

${vendorBids.map(b => `  • ${b.project} | ${b.division ? b.division + ' — ' : ''}${b.trade}`).join('\n')}

We are currently in active buyout and would appreciate receiving your bid at your earliest convenience. If you have any questions about the scope or drawings, please don't hesitate to reach out.

If you are not able to bid this project, please let us know so we can plan accordingly.

Thank you,
Buck Adams
Hendrickson Construction Inc.
buck@hendricksoninc.com`;

    drafts.push({ toEmail: email, subject, body, vendor: first.vendor, tradeLine, count: vendorBids.length });
}

return drafts.map(d => ({ json: d }));

